}
    }
    )
    }
    

    override fun `reset`()
        = 
    callWithHandle {
    uniffiRustCall() { _status ->
    UniffiLib.uniffi_tracelet_core_fn_method_locationprocessor_reset(
        it,
        _status)
}
    }
    
    

    

    


    
    
    /**
     * @suppress
     */
    companion object
    
}


/**
 * @suppress
 */
public object FfiConverterTypeLocationProcessor: FfiConverter<LocationProcessor, Long> {
    override fun lower(value: LocationProcessor): Long {
        return value.uniffiCloneHandle()
    }

    override fun lift(value: Long): LocationProcessor {
        return LocationProcessor(UniffiWithHandle, value)
    }

    override fun read(buf: ByteBuffer): LocationProcessor {
        return lift(buf.getLong())
    }

    override fun allocationSize(value: LocationProcessor) = 8UL

    override fun write(value: LocationProcessor, buf: ByteBuffer) {
        buf.putLong(lower(value))
    }
}



