 */
public object FfiConverterSequenceTypeCoordinate: FfiConverterRustBuffer<List<Coordinate>> {
    override fun read(buf: ByteBuffer): List<Coordinate> {
        val len = buf.getInt()
        return List<Coordinate>(len) {
            FfiConverterTypeCoordinate.read(buf)
        }
    }

    override fun allocationSize(value: List<Coordinate>): ULong {
        val sizeForLength = 4UL
        val sizeForItems = value.map { FfiConverterTypeCoordinate.allocationSize(it) }.sum()
        return sizeForLength + sizeForItems
    }

    override fun write(value: List<Coordinate>, buf: ByteBuffer) {
        buf.putInt(value.size)
        value.iterator().forEach {
            FfiConverterTypeCoordinate.write(it, buf)
        }
    }
